import React,{useState} from 'react'

const Taskcard = ({ task }) => {
    return (
        <>
            <div className='task-card'>
                <div className='taskcard-header'>
                    <div className='task-title'>
                        {task.title}
                    </div>
                    <div className='task-icons'>
                        <div className='sub-icon'>
                            <button className='icon-button'>
                                <img className='icon-img' src='/assets/add.png' alt="Add" />
                            </button>
                        </div>
                        <div className='sub-icon'>
                            <button className='icon-button'>
                                <img className='icon-img' src='/assets/edit.png'></img>
                            </button>
                        </div>
                        <div className='sub-icon'>
                            <button className='icon-button'>
                                <img className='icon-img' src='./assets/delete.png'></img>
                            </button>
                        </div>
                    </div>
                </div>
                <div className='sub-tasks'>
                    <ul>
                        <input type='checkbox'/>
                    </ul>
                </div>
            </div>
            <Stylesheet />
        </>
    )
}

const Stylesheet = () => {
    return <style>{`
        .task-card {
            margin-bottom: 2rem;
            // width: 270px;
            // border: 1px solid #ccc;
            // border-radius: 5px;
            padding: 10px;
            background-color: var(--secondary-color, #f9f9f9);
            box-sizing: border-box;
        }
        .taskcard-header{
           display:flex;
           align-items:center;
           justify-content:space-between;
            padding-left:5px;
            padding-right:5px;
            flex-direction:row;
            background-color:var(--secondary-color);
            width:250px;
            min-height:50px;
            border-radius: 5px;
        }
        .task-icons{
          display:flex;
          align-items:center;
        }
        .icon-button{
            background:none;
            border:none;
        }

        .icon-img{
            height:20px;
            width:30px;
        }
        .task-title{
            width:100px;
            word-wrap: break-word;
            overflow-wrap: break-word;
            white-space: normal;
        }
        .sub-tasks{
           display:flex;
           justify-content:left;
           align-items:center;
           background-color:yellow;
        }
            
    `}
    </style>
}

export default Taskcard


